script:
(function () {
  function createHeroMarkup() {
    return '' +
      '<section class="cuiabar-home-hero" id="cuiabar-home-hero">' +
        '<p class="cuiabar-kicker">blog.cuiabar.com</p>' +
        '<h2>Um hub editorial da Cuiabar para agenda, gastronomia e descoberta local.</h2>' +
        '<p>Use esta faixa como abertura do blog no Blogger. Ela puxa o leitor para o clima da marca e organiza a entrada para menu, reservas, agenda e canal oficial sem poluir o site principal.</p>' +
        '<div class="cuiabar-action-row">' +
          '<a class="cuiabar-button" href="https://reservas.cuiabar.com">Reservar mesa</a>' +
          '<a class="cuiabar-button-secondary" href="https://cuiabar.com/menu">Abrir menu</a>' +
          '<a class="cuiabar-button-secondary" href="https://cuiabar.com/agenda">Ver agenda</a>' +
        '</div>' +
        '<div class="cuiabar-meta-row">' +
          '<span class="cuiabar-chip">Agenda e pautas locais</span>' +
          '<span class="cuiabar-chip">Clima e contexto</span>' +
          '<span class="cuiabar-chip">Monetizacao com anuncios</span>' +
        '</div>' +
        '<div class="cuiabar-spotlight-grid">' +
          '<article class="cuiabar-mini-panel">' +
            '<p class="cuiabar-kicker">Distribuicao</p>' +
            '<h3>Canal no WhatsApp</h3>' +
            '<p>Divulgue agenda, especiais e novos artigos usando o canal oficial como motor recorrente.</p>' +
          '</article>' +
          '<article class="cuiabar-mini-panel">' +
            '<p class="cuiabar-kicker">Conversao</p>' +
            '<h3>Reserva e menu</h3>' +
            '<p>Todo conteudo pode terminar com CTA forte para reserva, cardapio ou contato comercial.</p>' +
          '</article>' +
          '<article class="cuiabar-mini-panel">' +
            '<p class="cuiabar-kicker">Receita</p>' +
            '<h3>Zona para AdSense</h3>' +
            '<p>O tema ja fica pronto para encaixar Auto ads ou blocos manuais sem quebrar o visual.</p>' +
          '</article>' +
        '</div>' +
      '</section>';
  }

  function createSideMarkup() {
    return '' +
      '<aside class="cuiabar-side-card" id="cuiabar-side-card">' +
        '<p class="cuiabar-kicker">Villa Cuiabar</p>' +
        '<h3>Continue a experiencia fora do artigo</h3>' +
        '<p>Use este bloco para puxar o leitor para reserva, agenda e canal oficial.</p>' +
        '<a href="https://reservas.cuiabar.com">Reservar agora</a>' +
      '</aside>';
  }

  function createFooterMarkup() {
    return '' +
      '<section class="cuiabar-footer-band" id="cuiabar-footer-band">' +
        '<p class="cuiabar-kicker">Laboratorio editorial Cuiabar</p>' +
        '<h3>Conteudo com identidade de marca e rota curta para conversao.</h3>' +
        '<p>O blog pode funcionar como base editorial, descoberta organica e ainda abrir espaco para anuncios, publis e campanhas sazonais sem depender de desenvolver um app editorial inteiro do zero.</p>' +
        '<div class="cuiabar-action-row">' +
          '<a class="cuiabar-button" href="https://cuiabar.com">Site principal</a>' +
          '<a class="cuiabar-button-secondary" href="https://whatsapp.com/channel/0029VbAcHLXFSAsxCt6lly0a">Canal WhatsApp</a>' +
        '</div>' +
      '</section>';
  }

  function tryInject() {
    if (!document.body) {
      return false;
    }

    var heroAnchor = document.querySelector('.blog-posts, .posts, .main-inner, .main, [id*="Blog"], .widget.Blog');
    if (heroAnchor && !document.getElementById('cuiabar-home-hero')) {
      heroAnchor.insertAdjacentHTML('beforebegin', createHeroMarkup());
    }

    var sideAnchor = document.querySelector('.sidebar, .sidebar-container, .sidebar-right, [id*="sidebar"]');
    if (sideAnchor && !document.getElementById('cuiabar-side-card')) {
      sideAnchor.insertAdjacentHTML('afterbegin', createSideMarkup());
    }

    var footerAnchor = document.querySelector('footer, .footer, .footer-outer, .main-inner, .content-inner');
    if (footerAnchor && !document.getElementById('cuiabar-footer-band')) {
      footerAnchor.insertAdjacentHTML('beforeend', createFooterMarkup());
    }

    return Boolean(document.getElementById('cuiabar-home-hero'));
  }

  if (!tryInject()) {
    document.addEventListener('DOMContentLoaded', function () {
      tryInject();
      window.setTimeout(tryInject, 900);
      window.setTimeout(tryInject, 2200);
    });
  }
})();
